insert into public.species
  (slug, name_ko, name_en, scientific_name, size_cm, lifespan_years, temperament, origin, summary, description, care_tips)
values
  ('golden-black',       '골든블랙햄스터',         'Black Syrian Hamster',         'Mesocricetus auratus',  '15–20cm', '2–3년', '순함, 단독사육',     '시리아',   '시리안 햄스터의 검은색 변이로 광택 있는 흑모가 특징.',                                              '시리안 햄스터의 검은색 변이. 새끼 때는 짙은 회색에서 자라며 검게 변하는 경우도 있다. 시리안의 모든 특성을 그대로 가진다.',                                                                                              '단독 사육 필수, 60×40cm 이상 케이지 권장. 톱밥 깊이 15cm 이상으로 굴 파기 본능을 충족시킨다.'),
  ('golden-satin',       '골든사틴햄스터',         'Satin Syrian Hamster',         'Mesocricetus auratus',  '15–20cm', '2–3년', '순함, 느긋함',       '시리아',   '광택 나는 사틴 모질의 시리안 햄스터.',                                                              '털이 비단처럼 광택을 띠는 모질 변이. 일반 시리안보다 털이 약간 더 가늘다. 사틴×사틴 교배는 권장되지 않는다.',                                                                                                       '브러시는 불필요하나 케이지 청결 유지가 중요. 단독 사육이 필수다.'),
  ('golden-syrian',      '골든시리안햄스터',       'Golden Syrian Hamster',        'Mesocricetus auratus',  '15–20cm', '2–3년', '순함, 핸들링 용이',  '시리아',   '한국에서 가장 흔히 키우는 대형 햄스터. 황금빛 털이 특징.',                                          '시리안 햄스터의 원종 컬러. 초보자에게 가장 추천되는 종으로 핸들링이 쉽고 야행성이 비교적 약하다. 반드시 단독 사육해야 한다.',                                                                                          '60×40cm 이상의 큰 케이지, 20cm 이상 깊은 베딩, 직경 20cm 이상의 휠을 권장한다.'),
  ('chinese-hamster',    '그레이햄스터',           'Chinese Hamster (Grey)',       'Cricetulus griseus',    '10–12cm', '2–3년', '겁 많음, 순함',      '중국 북부','꼬리가 길고 등에 검은 줄무늬가 있는 햄스터.',                                                        '드워프로 분류되지만 분류학적으로는 별도 속(Cricetulus)이다. 꼬리가 약 2cm로 햄스터 중 가장 길다. 점프력이 좋아 탈출에 주의.',                                                                                       '높이가 낮고 뚜껑이 단단한 케이지를 사용한다. 손에 익히면 손 위에 가만히 머무는 경우가 많다.'),
  ('long-haired-black',  '노블랙시리안햄스터',     'Long-haired Black Syrian',     'Mesocricetus auratus',  '15–20cm', '2–3년', '순함, 느긋함',       '시리아',   '검은 장모를 가진 시리안 햄스터 변이.',                                                              '시리안의 검은색×장모 교배 변이. 수컷이 암컷보다 털이 더 길다. 털 관리가 필요하다.',                                                                                                                                  '주 1회 이상 부드러운 칫솔로 빗어주고, 베딩에 털이 엉키지 않도록 자주 갈아준다.'),
  ('dove-winter-white',  '도브윈터화이트햄스터',   'Dove Winter White',            'Phodopus sungorus',     '7–10cm',  '1.5–2년','활발, 다소 예민',    '러시아·카자흐스탄','은은한 연보랏빛 회색이 도는 윈터화이트 변이.',                                                       '윈터화이트(정글리안)의 도브 컬러 변이. 추운 환경에서 털이 더 옅어진다. 작고 활발하지만 길들이려면 인내가 필요하다.',                                                                                              '40×30cm 이상 깊은 베딩 케이지. 직경 16cm 이상의 휠 권장. 당뇨 위험이 있으니 과일·당분 제한.'),
  ('djungarian',         '드워프윈터화이트햄스터', 'Dwarf Winter White',           'Phodopus sungorus',     '7–10cm',  '1.5–2년','활발, 호기심 많음',  '러시아·카자흐스탄','겨울에 털이 하얗게 변하는 작은 햄스터.',                                                             '계절에 따라 털 색이 변하는 특성이 있으며 등에 검은 줄이 희미하게 남는다. 윈터화이트와 정글리안은 동의어이나 혈통 차이로 구분되기도 한다.',                                                                       '잡식이지만 당뇨가 잘 오므로 과일 간식은 주 1회 이내로 제한한다.'),
  ('light-brown',        '라이트브라운햄스터',     'Light Brown Hamster',          'Mesocricetus auratus',  '15–20cm', '2–3년', '순함',               '시리아',   '연한 갈색 톤의 시리안 햄스터.',                                                                     '시리안 햄스터의 연갈색 변이. 일명 시나몬 컬러라고도 부른다. 부드러운 인상을 준다.',                                                                                                                                  '시리안 햄스터 사육 기준과 동일. 단독 사육 필수.'),
  ('roborovski',         '로보로브스키햄스터',     'Roborovski Hamster',           'Phodopus roborovskii',  '4–5cm',   '3–3.5년','매우 빠름, 예민',    '몽골',     '햄스터 중 가장 작고 빠른 종. 핸들링보다 관찰형.',                                                   '햄스터 중 가장 작고 가장 오래 사는 편. 무리 사육이 가능하나 성별 분리 필수이며 싸움도 잦다.',                                                                                                                       '탈출 방지를 위해 빈틈 없는 케이지 필수. 모래 목욕장을 매일 제공한다.'),
  ('roborovski-wf',      '로보로브스키화이트페이스','White-faced Roborovski',       'Phodopus roborovskii',  '4–5cm',   '3–3.5년','매우 빠름, 예민',    '몽골',     '얼굴이 하얀 로보로브스키 변이.',                                                                    '로보로브스키의 얼굴 흰색 변이. 눈 주위와 콧등이 흰색으로 더 귀여운 인상을 준다.',                                                                                                                                    '일반 로보와 동일하게 모래 목욕과 작은 휠(직경 14cm 이상)을 제공한다.'),
  ('long-haired-syrian', '롱헤어시리안햄스터',     'Long-haired Syrian',           'Mesocricetus auratus',  '15–22cm', '2–3년', '순함, 느긋함',       '시리아',   '긴 털을 가진 시리안. 수컷의 털이 더 길다.',                                                         '일명 ‘테디베어’와 종종 혼용되며, 장모 유전자를 가진 시리안. 수컷이 눈에 띄게 더 풍성하다.',                                                                                                                          '베딩이 털에 엉키지 않도록 작은 칩 베딩보다 종이류 베딩을 권장. 부드러운 빗으로 주 1회 정도 빗어준다.'),
  ('manchurian',         '망토햄스터',             'Manchurian Hamster',           'Cricetulus eversmanni', '8–11cm',  '2–3년', '온순, 야행성 강함',  '동아시아', '한국·만주 지역에 자생했던 야생 햄스터(국내 분양은 드묾).',                                          '국내 분양은 매우 드물고 학술 자료에서 주로 언급되는 종. 야생 개체 보호 차원에서 분양 자제가 권장된다.',                                                                                                              '국내 분양이 거의 없으므로 정보 차원으로만 보관한다.'),
  ('mosaic',             '모자이크햄스터',         'Mosaic Hamster',               'Mesocricetus auratus',  '15–20cm', '2–3년', '순함',               '시리아',   '여러 색이 패치워크처럼 섞인 시리안 변이.',                                                          '모자이크 유전자가 발현된 시리안. 같은 부모에게서 태어나도 무늬가 모두 다르다.',                                                                                                                                      '시리안 사육 기준과 동일. 강한 햇빛에 두면 무늬 색이 바랠 수 있다.'),
  ('banded-syrian',      '밴디드시리안햄스터',     'Banded Syrian',                'Mesocricetus auratus',  '15–20cm', '2–3년', '순함',               '시리아',   '몸 중앙에 흰 띠가 있는 시리안 변이.',                                                               '복부와 몸통에 흰 띠가 둘러진 패턴. 일명 ‘판다 햄스터’라고도 부른다.',                                                                                                                                                '시리안 사육 기준과 동일. 단독 사육 필수.'),
  ('black-bear',         '블랙베어햄스터',         'Black Bear Hamster',           'Mesocricetus auratus',  '15–20cm', '2–3년', '온순, 게으른 편',    '시리아',   '검은 곰 같은 외모의 시리안 변이. 미국에서 정착된 라인.',                                            '검은색 시리안 중 특히 둥글고 통통한 체형의 라인. 성격이 차분한 편이라 핸들링 입문용으로도 추천된다.',                                                                                                              '비만에 주의. 운동량 확보를 위해 큰 휠과 넓은 케이지를 제공한다.'),
  ('black-syrian',       '블랙시리안햄스터',       'Black Syrian',                 'Mesocricetus auratus',  '15–20cm', '2–3년', '순함',               '시리아',   '전신이 검은 시리안. 발끝에 흰 점이 있는 개체가 많다.',                                              '시리안의 검은색 단모 변이. 흔히 블랙베어와 혼용되나, 블랙베어는 미국 라인 명칭이다.',                                                                                                                              '햇빛에 장시간 노출되면 털끝이 갈색으로 바랠 수 있다.'),
  ('satin-winter-white', '사틴윈터화이트햄스터',   'Satin Winter White',           'Phodopus sungorus',     '7–10cm',  '1.5–2년','활발',               '러시아·카자흐스탄','광택 있는 모질의 윈터화이트 변이.',                                                                  '사틴 모질의 윈터화이트. 빛에 따라 털이 매끄럽게 빛난다.',                                                                                                                                                            '윈터화이트 사육 기준과 동일. 당뇨 위험 주의.'),
  ('siamese',            '샴햄스터',               'Siamese Hamster',              'Mesocricetus auratus',  '15–20cm', '2–3년', '순함',               '시리아',   '얼굴·귀·발끝이 짙은 시리안 변이. 샴고양이 패턴과 닮음.',                                            '체온이 낮은 부위(귀·코·발)가 짙어지는 시리안의 컬러포인트 패턴. 새끼 때는 거의 흰색.',                                                                                                                              '시리안 사육 기준과 동일. 단독 사육 필수.'),
  ('syrian-golden',      '시리안골든햄스터',       'Syrian Golden',                'Mesocricetus auratus',  '15–20cm', '2–3년', '순함, 핸들링 용이',  '시리아',   '골든시리안과 동일하나 ‘시리안’으로 더 자주 불리는 표기.',                                          '국내에서는 ‘시리안’ 표기와 ‘골든’ 표기가 동의어로 사용되며, 분양처마다 명칭이 다르다.',                                                                                                                              '단독 사육 필수. 65cm 이상의 케이지 권장.'),
  ('silver-fair',        '실버페어햄스터',         'Silver Fawn Syrian',           'Mesocricetus auratus',  '15–20cm', '2–3년', '순함',               '시리아',   '은은한 은빛 페어 컬러의 시리안 변이.',                                                              '시리안의 옅은 은회색 변이. 어린 시기에 가장 색이 진하며 자라며 옅어진다.',                                                                                                                                            '시리안 사육 기준과 동일. 햇빛에 직접 노출시키지 않는다.'),
  ('albino',             '알비노햄스터',           'Albino Hamster',               'Mesocricetus auratus',  '15–20cm', '2–3년', '순함, 시력 약함',    '시리아',   '눈이 빨갛고 털이 순백색인 시리안 변이.',                                                            '멜라닌이 결핍된 알비노. 시력이 약하므로 갑작스러운 움직임에 놀라기 쉽다.',                                                                                                                                            '강한 조명을 피하고 케이지 위치를 자주 바꾸지 않는다.'),
  ('yellow-campbell',    '옐로우캠벨햄스터',       'Yellow Campbell',              'Phodopus campbelli',    '7–10cm',  '1.5–2년','활발, 영역 강함',    '몽골',     '연한 노란 베이지색의 캠벨 햄스터.',                                                                 '캠벨의 옐로우 라인. 캠벨은 윈터화이트보다 영역 의식이 강하고 입질 가능성이 더 있다.',                                                                                                                                '당뇨에 매우 취약하므로 과일과 가공 간식은 피한다. 모래 목욕을 좋아한다.'),
  ('winter-white',       '윈터화이트햄스터',       'Winter White',                 'Phodopus sungorus',     '7–10cm',  '1.5–2년','활발, 다소 예민',    '러시아·카자흐스탄','겨울에 털이 하얗게 변하는 드워프 햄스터.',                                                            '드워프윈터화이트와 동일종이지만, 표기 차이로 분리해 구분하는 분양처가 있다. 정글리안과 동의어로도 쓰인다.',                                                                                                            '실내 온도가 따뜻하면 털 색 변화는 잘 일어나지 않는다.'),
  ('jungarian',          '정글리안햄스터',         'Djungarian Hamster',           'Phodopus sungorus',     '7–10cm',  '1.5–2년','활발, 호기심 많음',  '러시아·카자흐스탄','윈터화이트의 다른 이름. 야생 컬러를 강조하는 표기.',                                                '정글리안은 윈터화이트의 학명에서 유래한 이름이며 야생색(아구티)에 가까운 라인을 가리키는 경우가 많다.',                                                                                                                '윈터화이트와 사육법 동일. 깊은 베딩 권장.'),
  ('chinese',            '중국햄스터',             'Chinese Hamster',              'Cricetulus griseus',    '10–12cm', '2–3년', '겁 많지만 순함',     '중국 북부','꼬리가 긴 진짜 ‘중국’ 햄스터. 그레이햄스터와 동일종.',                                                '드워프 분류이지만 별도 속에 속한다. 꼬리가 길고 몸이 가늘다. 점프력에 주의해야 한다.',                                                                                                                                '높이가 낮은 케이지로 추락 위험을 줄인다. 모래 목욕을 좋아한다.'),
  ('campbell-dwarf',     '캠벨드워프햄스터',       'Campbell Dwarf',               'Phodopus campbelli',    '7–10cm',  '1.5–2년','활발, 영역 강함',    '몽골·러시아','윈터화이트와 매우 닮았지만 더 까칠한 드워프.',                                                       '윈터화이트와 흔히 혼동되나 등 줄무늬, 귀 색상, 성격에서 차이가 난다. 핸들링은 시간이 필요하다.',                                                                                                                      '단독 사육이 안전. 손에 익히려면 매일 짧고 일관된 핸들링이 필요하다.'),
  ('campbell-wb',        '캠벨화이트벨리햄스터',   'Campbell White-bellied',       'Phodopus campbelli',    '7–10cm',  '1.5–2년','활발',               '몽골',     '배가 흰색이 강조된 캠벨 변이.',                                                                     '복부 흰색이 옆구리까지 깔끔하게 올라온 라인. 한국 분양처에서 인기가 있다.',                                                                                                                                            '캠벨 사육 기준과 동일. 당분 간식 제한.'),
  ('cream',              '크림햄스터',             'Cream Syrian',                 'Mesocricetus auratus',  '15–20cm', '2–3년', '순함',               '시리아',   '연한 크림색의 시리안 햄스터.',                                                                      '시리안의 옅은 크림색 변이. 햇빛에 따라 따뜻한 톤으로 보인다.',                                                                                                                                                        '시리안 사육 기준과 동일.'),
  ('tortoiseshell',      '토토이즈쉘햄스터',       'Tortoiseshell Syrian',         'Mesocricetus auratus',  '15–20cm', '2–3년', '순함',               '시리아',   '여러 색이 거북등껍질처럼 섞인 시리안.',                                                             '모자이크와 유사하지만 토토이즈쉘은 노랑·검정·흰색이 동시에 나타나는 특정 패턴을 가리킨다.',                                                                                                                          '시리안 사육 기준과 동일. 단독 사육 필수.'),
  ('teddy-bear',         '테디베어햄스터',         'Teddy Bear Hamster',           'Mesocricetus auratus',  '15–22cm', '2–3년', '온순, 느긋함',       '시리아',   '풍성한 장모를 가진 시리안의 별칭.',                                                                 '북미·한국에서 장모 시리안을 부르는 별칭. 분류상 시리안과 동일하나 매장 표기로 자주 쓰인다.',                                                                                                                          '털 관리가 필요하므로 종이류 베딩 권장. 정기적인 빗질을 한다.'),
  ('pearl-winter-white', '펄윈터화이트햄스터',     'Pearl Winter White',           'Phodopus sungorus',     '7–10cm',  '1.5–2년','활발',               '러시아·카자흐스탄','진주처럼 흰빛이 강한 윈터화이트 변이.',                                                              '겨울이 아니어도 흰색에 가까운 윈터화이트 라인. 등 줄이 거의 보이지 않는다.',                                                                                                                                          '윈터화이트 사육 기준과 동일.')
